arguments.typescript:
const result = await api.getTargetChannel();
const channelId = result.channelId;

const now = new Date();
const toIso = now.toISOString();
const fromIso = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();

const summaryResult = await api.summarizeChannel({ channelId, fromIso, toIso });

return {
  channelId: summaryResult.channelId,
  fromIso: summaryResult.fromIso,
  toIso: summaryResult.toIso,
  summary: summaryResult.summary,
  topics: summaryResult.topics,
  actionItems: summaryResult.actionItems
};

